  ('disabled-e0adf6cd-moex-00108', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '甲在河流旁搭建工寮並開闢菜園，經主管機關認定妨害水土保持屬於違 法，命甲限期回復原狀。甲不服，除循序提起訴願救濟外，得以下列何種 程序在救濟進行期間實現暫時權利保護？', '["應向行政法院聲請定暫時狀態假處分，由法院裁定該工寮及菜園暫時為 合法", "應向行政法院聲請保全處分，保全工寮及菜園之事實狀態", "應依據行政執行法向主管機關聲明異議", "應依行政訴訟法或訴願法聲請暫時停止執行該命回復原狀之處分 30830"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00109', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者非屬確認行政處分無效之訴的實體判決要件？', '["確認對象須為行政處分之無效", "須已向原處分機關請求確認其無效未被允許或不為確答", "須經訴願程序而遭駁回", "須有即受確認判決之法律上利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00110', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於行政訴訟制度之敘述，下列何者正確？', '["收容聲請事件適用以原就被之原則", "對於已執行而無回復原狀可能之行政處分，得提起確認該行政處分無效 之訴訟", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允 許，或經請求後於30日內不為確答者，始得提起之", "受交通違規裁罰處分，應先經訴願程序，始得提起行政訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00111', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於國家賠償法所規定之公共設施國家賠償責任，下列何者正確？', '["當公共設施已委託民間團體或個人管理時，國家即免除損害賠償責任", "於開放之山域、水域等自然公物，經管理機關、受委託管理之民間團體 或個人已就使用該公物為適當之警告或標示，而人民仍從事冒險或具危 險性活動，國家不負損害賠償責任", "於開放之山域、水域等自然公物內之設施，經管理機關、受委託管理之 民間團體或個人已就使用該公物為適當之警告或標示，而人民仍從事冒 險或具危險性活動，國家不負損害賠償責任", "就公共設施設置或管理之瑕疵應負責之第三人，賠償機關對之並無求 償權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00112', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-113-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["錯誤施打疫苗造成人民身體健康受損，基於準徵收法理應予補償", "對於犯罪被害人所為之補償，非基於特別犧牲", "土地徵收為合法、有目的性對人民財產權之侵害，故須給予補償", "為防止公益重大危害而廢止授益處分時，受益人得請求信賴利益損失 補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00113', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-112-856e6567', 'sub-disabled-e0adf6cd-02', NULL, 'essay', '「教育」與「哲學」之關係極為密切，試列舉五種關係，並進而合理性論
